<?php require_once 'db.php'; verify_csrf(); $token=$_GET['token']??$_POST['token']??''; if($_SERVER['REQUEST_METHOD']==='POST'){ $otp=trim($_POST['otp']??''); $pass=$_POST['password']??''; $s=pdo()->prepare('SELECT pr.*,u.email FROM password_resets pr JOIN users u ON u.id=pr.user_id WHERE pr.token=? AND (pr.otp=? OR ?="") AND pr.used_at IS NULL AND pr.expires_at>NOW()'); $s->execute([$token,$otp,$otp]); if(($r=$s->fetch())&&strlen($pass)>=8){ pdo()->prepare('UPDATE users SET password=? WHERE id=?')->execute([password_hash($pass,PASSWORD_DEFAULT),$r['user_id']]); pdo()->prepare('UPDATE password_resets SET used_at=NOW() WHERE id=?')->execute([$r['id']]); flash('Password reset successful. Login now.'); header('Location: login.php'); exit; } flash('Invalid or expired reset token/OTP.','err'); } app_header('Reset Password'); ?><form class="auth card" method="post"><h1>Reset Password</h1><?=csrf_field()?><input name="token" value="<?=e($token)?>" placeholder="Reset token" required><input name="otp" placeholder="OTP (optional if link token is used)"><input name="password" type="password" minlength="8" placeholder="New password" required><button class="btn">Reset password</button></form><?php app_footer(); ?>
